197→bool ALFPTacticsUnit::MoveToTile(ALFPHexTile* NewTargetTile)
198→{
199→    if (!NewTargetTile || !HasEnoughMovePoints(1)) return false;
200→
201→    ALFPHexGridManager* GridManager = GetGridManager();
202→    if (!GridManager) return false;
203→
204→    // 获取当前所在的格子
205→    ALFPHexTile* CurrentTile = GridManager->GetTileAtCoordinates(CurrentCoordinates);
206→    if (!CurrentTile) return false;
207→
208→    // 寻找路径
209→    MovePath = GridManager->FindPath(CurrentTile, NewTargetTile);
210→    // 计算路径实际移动代价（考虑地形）
211→    int32 PathCost = 0;
212→    for (ALFPHexTile* Tile : MovePath)
213→    {
214→        PathCost += Tile->GetMovementCost();
215→    }
216→    if (MovePath.Num() == 0 || PathCost > CurrentMovePoints) return false;
217→
218→    // 设置移动状态
219→    CurrentTile->SetIsOccupied(false);
220→    TargetTile = NewTargetTile;
221→    CurrentPathIndex = 0;
222→    MoveProgress = 0.0f;
223→    MovementRangeTiles.Empty();
