478→{
479→    if (bIsDead) return;
480→
481→	// 计算实际伤害（考虑防御）
482→	int32 ActualDamage = FMath::Max(Damage - Defense, 1);
483→	int32 OldHealth = CurrentHealth;
484→	CurrentHealth = FMath::Max(CurrentHealth - ActualDamage, 0);
485→
486→	// 广播血量变化事件
487→	OnHealthChangedDelegate.Broadcast(CurrentHealth, MaxHealth);
488→
489→	// 蓝图事件
490→	OnTakeDamage(ActualDamage);
491→
492→	// 检查死亡
493→	if (CurrentHealth <= 0)
494→	{
495→		HandleDeath();
496→	}
497→}
